<template>
    <div class="w-full bg-lightblue border-b-2 border-dark mt-20 mb-10 p-2 input_field">
      <label for="login-username" class="text-dark text-center block">Username</label>
      <input
          id="login-username"
          v-model="username"
          class="w-full bg-lightblue text-lg text-center"
          type="text"
          ref="username"
          autocomplete="username"
          @keydown.enter="$refs.password.focus()"
      />
    </div>
    <div class="w-full bg-lightblue border-b-2 border-dark mt-10 mb-2 p-2 input_field">
      <label for="login-password" class="text-dark text-center block">Password</label>
      <input
          id="login-password"
          v-model="password"
          class="w-full bg-lightblue text-lg text-center"
          :type="revealPassword ? 'text' : 'password'"
          ref="password"
          autocomplete="current-password"
          @keydown.enter="signIn"
      />
    </div>
    <div class="flex justify-end mb-6">
      <button
        type="button"
        @click="revealPassword = !revealPassword"
        class="text-blue text-sm flat-btn"
        :aria-pressed="revealPassword"
      >
        <i :class="revealPassword ? 'fas fa-eye-slash' : 'fas fa-eye'" aria-hidden="true"></i>
        {{ revealPassword ? "Hide password" : "Reveal password" }}
      </button>
    </div>
    <div class="flex justify-center mt-6">
      <button
        v-if="!isLoading"
        @click.prevent="signIn"
        class="w-full md:w-1/3 font-bold rounded-full bg-blue text-white p-3 hover:bg-darkblue"
      >
        Log in
      </button>
      <div v-else class="w-full rounded-full mt-4 py-3">
        <ProgressBar/>
      </div>
    </div>
    <div v-if="showErrorModal" class="mt-4 p-3 rounded-lg bg-red-50 border border-red-200 text-center" role="alert">
      <p class="text-red-700 text-sm font-medium">{{ errorMessage }}</p>
      <button type="button" @click="showErrorModal = false" class="mt-2 text-xs text-red-500 hover:text-red-700 underline flat-btn">
        Dismiss
      </button>
    </div>
  </template>

<script>
import {defineAsyncComponent} from "vue";
import {warpnetService} from "@/service/service";
export default {
  name: "LogInComponent",
  components: {
    ProgressBar: defineAsyncComponent(() => import('./ProgressBar.vue')),
  },
  data() {
    return {
      username: "",
      password: "",
      revealPassword: false,
      isLoading: false,
      showErrorModal: false,
      errorMessage: "",
    };
  },
  created: function () {
    this.$nextTick(() => this.$refs.username.focus());
  },
  methods: {
    async signIn() {
      this.isLoading = true;
      this.showErrorModal = false;
      try {
        await warpnetService.signInUser({username: this.username, password: this.password});
        this.$router.push({ name: "Home" });
      } catch (error) {
        console.log("error signing in", error);
        this.errorMessage = error?.message || "Unknown error during sign-in.";
        this.showErrorModal = true;
      } finally {
        this.isLoading = false;
      }
    },
  },
};
</script>

<style scoped>
  .input_field {
    border-radius: 20px;
  }
  input:-webkit-autofill {
    background-color: #f4d5e1 !important;
    -webkit-box-shadow: 0 0 0px 1000px #f4d5e1 inset !important;
    border-radius: 8px;
  }
